mapper.insert:

	SELECT
	    'ROOM' || LPAD((COALESCE(MAX(CAST(SUBSTRING(room_id FROM 5) AS INTEGER)), 0) + 1)::text, 2, '0')
	FROM
	    MEETING_ROOM

INSERT INTO
	MEETING_ROOM (
		ROOM_ID
		, ROOM_NAME
		, LOCATION
		, CAPACITY
		, USE_YN
	) VALUES (
		#{roomId}
		, #{roomName}
		, #{location}
		, #{capacity}
		, COALESCE(#{useYn}, 'Y')
	)

mapper.update:
UPDATE
	MEETING_ROOM
SET
	ROOM_NAME = #{roomName}
	, LOCATION = #{location}
	, CAPACITY = #{capacity}
WHERE
	ROOM_ID = #{roomId}

UPDATE
	MEETING_ROOM
SET


		, USE_YN = #{useYn}


		, DEL_YN = #{delYn}
		, DEL_DT = CURRENT_TIMESTAMP


WHERE
	ROOM_ID = #{roomId}
